pub async fn list_users(pool: &sqlx::PgPool) -> Result<Vec<ListUsersRow>, sqlx::Error> {
    sqlx::query_as!(ListUsersRow, "SELECT id, name, email, created_at FROM users ORDER BY created_at DESC")
        .fetch_all(pool)
        .await
}

